  RVTEST_SIGUPD_CSR_READ(satp, x30, SPMPSm_paging_cg_cp_satp_bare_spmp_satp_bare_mmode_check, SPMPSm_paging_cg_cp_satp_bare_spmp_satp_bare_mmode_check_str)
  RVTEST_GOTO_LOWER_MODE Smode

